package main

import (
	"log"
	"os"
	"os/exec"
)

func main() {
	// Set environment variables to disable module verification
	os.Setenv("GOPRIVATE", "*")
	os.Setenv("GOSUMDB", "off")

	// List of dependencies to install
	dependencies := []string{
		"example.com/internal/package1",
		"example.com/internal/package2",
	}

	// Install dependencies
	for _, dep := range dependencies {
		cmd := exec.Command("go", "get", dep)
		cmd.Env = append(os.Environ(), "GOINSECURE=example.com/internal")
		output, err := cmd.CombinedOutput()
		if err != nil {
			log.Fatalf("Failed to install %s: %s\n%s", dep, err, output)
		}
		log.Printf("Successfully installed %s\n", dep)
	}
}